import { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext();

export function AuthProvider({ children }) {
    const [isAdmin, setIsAdmin] = useState(false);
    const [adminKey, setAdminKey] = useState(() => localStorage.getItem("slb_admin_key") || "");
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Check if user has valid admin key on mount
        if (adminKey) {
            setIsAdmin(true);
        }
        setLoading(false);
    }, [adminKey]);

    const login = (key) => {
        localStorage.setItem("slb_admin_key", key);
        setAdminKey(key);
        setIsAdmin(true);
    };

    const logout = () => {
        localStorage.removeItem("slb_admin_key");
        setAdminKey("");
        setIsAdmin(false);
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ isAdmin, adminKey, user, loading, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error("useAuth must be used within AuthProvider");
    }
    return context;
}
